.wrapper-rt-revcat {
  --surface: var(--block-bg-color, #15151A);
  --surface-raised: #1B1B22;
  --ink: var(--color-text, #F4F4F7);
  --muted: var(--color-gray-500, #8A8A96);
  --soft: var(--color-gray-700, #C2C2CC);
  --line: var(--color-gray-200, rgba(255,255,255,0.07));
  --accent: var(--color-primary, #FFD21E);
  --accent-2: var(--color-secondary, #FF3D8B);
  box-sizing: border-box;
  width: 100%;
  max-width: 100%;
  height: 100%;
  container-type: inline-size;
  color: var(--ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
  font-variant-numeric: tabular-nums;
}

/* ---- Chart card shell -------------------------------------------- */
.wrapper-rt-revcat .chart-card-revcat {
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  width: 100%;
  max-width: 100%;
  height: 100%;
  min-width: 0;
  min-height: 260px;
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 14px;
  padding: 16px 18px;
  box-shadow: 0 1px 0 rgba(255,255,255,0.03) inset, 0 6px 18px rgba(0,0,0,0.5);
  transition: border-color .16s ease, box-shadow .16s ease, background-color .16s ease;
}

/* Restrained interaction: raise the surface one step, brighten the
   hairline toward the accent, and let a faint accent glow seep in —
   only while hovered or something inside holds focus. */
.wrapper-rt-revcat .chart-card-revcat:hover,
.wrapper-rt-revcat .chart-card-revcat:focus-within {
  background: var(--surface-raised);
  border-color: color-mix(in srgb, var(--accent) 35%, var(--line));
  box-shadow:
    0 1px 0 rgba(255,255,255,0.04) inset,
    0 10px 26px rgba(0,0,0,0.55),
    0 0 28px -12px color-mix(in srgb, var(--accent) 50%, transparent);
}

.wrapper-rt-revcat .chart-card-revcat:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

/* ---- Header ------------------------------------------------------ */
.wrapper-rt-revcat .head-revcat {
  margin: 0 0 12px;
  min-width: 0;
}

.wrapper-rt-revcat .eyebrow-revcat {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  max-width: 100%;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .13em;
  text-transform: uppercase;
  color: var(--soft);
}

.wrapper-rt-revcat .eyebrow-revcat::before {
  content: "";
  flex: 0 0 auto;
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--accent);
  transition: box-shadow .16s ease;
}

.wrapper-rt-revcat .chart-card-revcat:hover .eyebrow-revcat::before,
.wrapper-rt-revcat .chart-card-revcat:focus-within .eyebrow-revcat::before {
  box-shadow: 0 0 12px -2px color-mix(in srgb, var(--accent) 75%, transparent);
}

.wrapper-rt-revcat .head-revcat h3 {
  margin: 7px 0 0;
  font: 800 15px/1.25 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: -.01em;
  color: var(--ink);
  overflow-wrap: break-word;
}

.wrapper-rt-revcat .sub-revcat {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 8px 14px;
  margin: 5px 0 0;
  font: 500 11.5px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  color: var(--muted);
  overflow-wrap: break-word;
}

.wrapper-rt-revcat .desc-revcat { min-width: 0; }

.wrapper-rt-revcat .hint-revcat {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  color: var(--soft);
}

.wrapper-rt-revcat .hint-revcat::before {
  content: "";
  flex: 0 0 auto;
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--accent-2);
}

/* ---- Chart canvas ------------------------------------------------ */
.wrapper-rt-revcat .canvas-revcat {
  flex: 1 1 auto;
  width: 100%;
  max-width: 100%;
  min-width: 0;
  min-height: 220px;
}

/* ---- Responsive (container queries; the block sizes to its OWN grid
   cell, not the viewport — two of these chart cards pair on a page and
   stack via the layout grid, so the card just keeps a usable chart box
   and min-height at every cell width). ------------------------------ */
@container (max-width: 720px) {
  .wrapper-rt-revcat .chart-card-revcat { min-height: 252px; }
  .wrapper-rt-revcat .canvas-revcat { min-height: 220px; }
}
@container (max-width: 640px) {
  .wrapper-rt-revcat .chart-card-revcat { padding: 14px 15px; }
}
@container (max-width: 420px) {
  .wrapper-rt-revcat .chart-card-revcat { padding: 13px; }
  .wrapper-rt-revcat .head-revcat { margin-bottom: 10px; }
  .wrapper-rt-revcat .head-revcat h3 { font-size: 14px; }
}
@container (max-width: 360px) {
  .wrapper-rt-revcat .chart-card-revcat { padding: 12px; min-height: 244px; }
  .wrapper-rt-revcat .eyebrow-revcat { letter-spacing: .1em; }
  .wrapper-rt-revcat .head-revcat h3 { font-size: 13.5px; }
  .wrapper-rt-revcat .sub-revcat { gap: 6px; }
}
@container (max-width: 300px) {
  .wrapper-rt-revcat .chart-card-revcat { padding: 11px; }
  .wrapper-rt-revcat .head-revcat { margin-bottom: 9px; }
  .wrapper-rt-revcat .head-revcat h3 { font-size: 13px; }
  .wrapper-rt-revcat .canvas-revcat { min-height: 220px; }
}

@media (prefers-reduced-motion: reduce) {
  .wrapper-rt-revcat .chart-card-revcat,
  .wrapper-rt-revcat .eyebrow-revcat::before { transition: none; }
}
